-- ﾔ碊ﾔ碊ﾔ碊 Fix: formato de hora sin segundos al llamar a upsert_agenda_reminders ﾔ碊ﾔ碊ﾔ碊ﾔ碊---- Problema:--   En create_agenda_activity_v2, p_time es time without time zone.--   Al hacer p_time::text, PostgreSQL incluye segundos: "09:44:00".--   calc_reminder_scheduled_at espera "HH:MM" y a+ｦade ":00",--   resultando en "09:44:00:00" ﾔ衄 error de parseo de timestamp.----   Error: invalid input syntax for type timestamp: "2026-05-08 09:44:00:00"---- Solucion: usar to_char(p_time, 'HH24:MI') en lugar de p_time::text.create or replace function public.create_agenda_activity_v2(  p_description       text,  p_event_date        date,  p_time              time without time zone,  p_time_end          text            default null,  p_priority          text            default 'media',  p_tipo              text            default 'actividad',  p_completed         boolean         default false,  p_result            text            default null,  p_assigned_user_ids bigint[]        default null,  p_visibility        text            default 'private',  p_reminder_minutes  integer         default null)returns public.agendalanguage plpgsqlsecurity definerset search_path = publicas $$declare  v_user_id     bigint;  v_empresa_id  bigint;  v_equipo_id   bigint;  v_assigned    bigint[];  v_result      public.agenda;begin  -- Contexto del usuario actual  select id, empresa_id, equipo_id  into v_user_id, v_empresa_id, v_equipo_id  from usuarios  where auth_id = auth.uid()    and estado = 'active'  limit 1;  if v_user_id is null then    raise exception 'Usuario no encontrado o inactivo';  end if;  -- Validar descripcion  if p_description is null or trim(p_description) = '' then    raise exception 'La descripcion es obligatoria';  end if;  -- Validar fecha  if p_event_date is null then    raise exception 'La fecha es obligatoria';  end if;  -- Al menos un usuario asignado  v_assigned := coalesce(p_assigned_user_ids, array[v_user_id]);  if array_length(v_assigned, 1) is null or array_length(v_assigned, 1) = 0 then    raise exception 'Debe asignarse al menos un usuario';  end if;  -- Insertar actividad  insert into agenda (    description, event_date, time, time_end,    priority, tipo, completed, result,    user_id, owner_user_id, empresa_id, equipo_id,    visibility, reminder_minutes_before  )  values (    trim(p_description),    p_event_date,    p_time,    nullif(trim(coalesce(p_time_end, '')), ''),    coalesce(nullif(p_priority, ''), 'media'),    coalesce(nullif(p_tipo, ''), 'actividad'),    coalesce(p_completed, false),    nullif(trim(coalesce(p_result, '')), ''),    v_assigned[1],    v_user_id,    v_empresa_id,    v_equipo_id,    coalesce(nullif(p_visibility, ''), 'private'),    p_reminder_minutes  )  returning * into v_result;  -- Insertar asignaciones  insert into agenda_usuarios (agenda_id, usuario_id)  select v_result.id, uid  from unnest(v_assigned) as uid  on conflict (agenda_id, usuario_id) do nothing;  -- Registrar recordatorio si aplica (formato HH:MM sin segundos)  if p_reminder_minutes is not null then    perform upsert_agenda_reminders(      v_result.id::integer,      p_event_date,      to_char(p_time, 'HH24:MI'),      p_reminder_minutes,      v_empresa_id::integer    );  end if;  return v_result;end;$$;comment on function public.create_agenda_activity_v2 is  'Crea actividad en agenda (v2). Fix: to_char(p_time, HH24:MI) para upsert_agenda_reminders.';notify pgrst, 'reload schema';